/**
 * Returns OHLCV price history for a specific cryptocurrency
 * @summary Get price history for a coin
 */
export const getGetCryptoHistoryUrl = (
  symbol: string,
  params?: GetCryptoHistoryParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/crypto/${symbol}/history?${stringifiedParams}`
    : `/api/crypto/${symbol}/history`;
};

